/**
 * TAPD 创建缺陷（Bug）脚本
 * 工作区：31253609（月圆之夜）
 */

import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const WS_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WS_DIR, 'tapd_cookies.json');
const WORKSPACE_ID = '31253609';
const BUG_CREATE_URL = `https://www.tapd.cn/${WORKSPACE_ID}/bugtrace/bugs/add`;

const STEALTH_SCRIPT = `
  Object.defineProperty(navigator, 'webdriver', { get: () => undefined });
  Object.defineProperty(navigator, 'plugins', { get: () => [1, 2, 3, 4, 5] });
  Object.defineProperty(navigator, 'languages', { get: () => ['zh-CN', 'zh', 'en'] });
  Object.defineProperty(navigator, 'hardwareConcurrency', { get: () => 8 });
  window.chrome = { runtime: {} };
`;

/**
 * 创建 Bug
 * @param {Object} opts
 * @param {string} opts.title - 标题（必填）
 * @param {string} [opts.handler='叶枝君'] - 处理人（姓名）
 * @param {string} [opts.cc='周以天;'] - 抄送（姓名;格式）
 * @param {string} [opts.priority='P2'] - 优先级
 * @param {string} [opts.version='【1V1】正式版本V2.0'] - 发现版本
 * @param {string} [opts.module='1V1'] - 模块
 * @param {string} [opts.branch='YZY_1V1 V1.0 Beta'] - 研发分支
 * @param {string} [opts.description=''] - 描述
 * @param {string[]} [opts.attachments=[]] - 附件路径列表
 * @returns {Promise<string>} Bug 详情页 URL
 */
export async function createBug(opts = {}) {
  const {
    title,
    handler = '叶枝君',
    cc = '周以天;',
    priority = 'P2',
    version = '【1V1】正式版本V2.0',
    module: mod = '1V1',
    branch = 'YZY_1V1 V1.0 Beta',
    description = '',
    attachments = [],
  } = opts;

  if (!title) throw new Error('title is required');

  // 读取 cookies
  if (!fs.existsSync(COOKIES_FILE)) {
    throw new Error(`Cookies file not found: ${COOKIES_FILE}`);
  }
  const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));

  const browser = await chromium.launch({
    headless: false,
    args: [
      '--no-sandbox',
      '--disable-blink-features=AutomationControlled',
      '--user-agent=Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
    ],
  });

  const context = await browser.newContext({
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
  });

  await context.addInitScript(STEALTH_SCRIPT);
  await context.addCookies(cookies);

  const page = await context.newPage();

  try {
    console.log('Opening bug create page...');
    await page.goto(BUG_CREATE_URL, { waitUntil: 'networkidle', timeout: 30000 });

    // 检查是否被重定向到登录页
    if (page.url().includes('login')) {
      throw new Error('TAPD session expired, please re-login');
    }

    // 填写标题
    await page.fill('#BugTitle', title);
    console.log(`Title: ${title}`);

    // 优先级
    await page.selectOption('#BugPriority', priority);
    console.log(`Priority: ${priority}`);

    // 发现版本
    try {
      // 先尝试 select
      await page.selectOption('#BugVersionReport', { label: version }, { timeout: 2000 });
    } catch {
      await page.fill('#BugVersionReport', version);
    }
    console.log(`Version: ${version}`);

    // 模块
    try {
      await page.selectOption('#BugModule', { label: mod }, { timeout: 2000 });
    } catch {
      await page.fill('#BugModule', mod);
    }
    console.log(`Module: ${mod}`);

    // 研发分支（自定义字段，select 类型）
    try {
      await page.selectOption('#BugCustomFieldOne', { label: branch }, { timeout: 3000 });
      console.log(`Branch: ${branch}`);
    } catch (e) {
      try {
        await page.fill('#BugCustomFieldOne', branch);
        console.log(`Branch (fill): ${branch}`);
      } catch (e2) {
        console.warn('Branch field not found, skipping:', e2.message);
      }
    }

    // 处理人（自动补全）
    // 始终在处理人中追加兵王(周以天)，确保 bug 单能流转到 QA
    const handlers = [handler, '周以天'].filter((v, i, arr) => arr.indexOf(v) === i); // 去重
    const ownerInput = page.locator('#BugCurrentOwnerValue').first();
    for (const h of handlers) {
      await ownerInput.click();
      await ownerInput.type(h, { delay: 120 });
      await page.waitForTimeout(2000); // 等待自动补全下拉
      await page.keyboard.press('Enter');
      await page.waitForTimeout(600);
      console.log(`Handler added: ${h}`);
    }
    console.log(`Handlers: ${handlers.join(', ')}`);

    // 抄送
    const ccInput = page.locator('#BugCcValue').first();
    await ccInput.click();
    await ccInput.type(cc.replace(/;$/, ''), { delay: 120 });
    await page.waitForTimeout(2000);
    await page.keyboard.press('Enter');
    await page.waitForTimeout(600);
    console.log(`CC: ${cc}`);

    // 描述
    if (description) {
      try {
        // 尝试富文本编辑器
        const descFrame = page.frameLocator('iframe[id*="BugDescription"], iframe[title*="description"]').first();
        await descFrame.locator('body').fill(description);
      } catch {
        try {
          await page.fill('#BugDescription', description);
        } catch (e) {
          console.warn('Description field not found:', e.message);
        }
      }
    }

    // 附件上传
    if (attachments.length > 0) {
      // 必须先点击上传触发按钮，否则文件内容为空
      const uploadTrigger = page.locator('#upload-attachement').first();
      if (await uploadTrigger.count() > 0) {
        await uploadTrigger.click();
        await page.waitForTimeout(1000);
      }
      for (const filePath of attachments) {
        if (fs.existsSync(filePath)) {
          console.log(`Uploading: ${filePath}`);
          await page.locator('#file_input').first().setInputFiles(filePath);
          await page.waitForTimeout(6000); // 等待 AJAX 上传到 file.tapd.cn
        } else {
          console.warn(`Attachment not found: ${filePath}`);
        }
      }
    }

    // 提交
    console.log('Submitting...');
    // 先截图看一下当前状态
    await page.screenshot({ path: path.join(WS_DIR, 'memory/tapd_before_submit.png') });
    // 点击「创建」按钮（可见的 <a> 链接）
    const submitBtn = page.locator('a#_view, a[onclick*="save_return"], a:has-text("创建")').first();
    await submitBtn.click();
    // 等待导航或成功提示
    try {
      await page.waitForNavigation({ waitUntil: 'networkidle', timeout: 20000 });
    } catch {
      // 可能是 AJAX 提交，不跳转，等待 URL 变化
      await page.waitForTimeout(3000);
    }

    const finalUrl = page.url();
    console.log(`Bug created: ${finalUrl}`);
    return finalUrl;

  } finally {
    await browser.close();
  }
}

// 直接运行时的入口
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const args = process.argv.slice(2);
  const title = args[0] || '测试 Bug';
  createBug({ title })
    .then(url => {
      console.log('SUCCESS:', url);
      process.exit(0);
    })
    .catch(err => {
      console.error('FAILED:', err.message);
      process.exit(1);
    });
}

