/**
 * 快速验证 TAPD cookie 是否有效
 */
import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const WS_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WS_DIR, 'tapd_cookies.json');

async function main() {
  const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));

  const browser = await chromium.launch({ headless: false, args: ['--no-sandbox'] });
  const context = await browser.newContext();

  // 添加所有 cookies
  for (const c of cookies) {
    try {
      await context.addCookies([{
        name: c.name,
        value: c.value,
        domain: c.domain,
        path: c.path || '/',
      }]);
    } catch (e) {
      console.warn(`Failed to add ${c.name}: ${e.message}`);
    }
  }

  const page = await context.newPage();

  // 测试访问 bug 创建页
  console.log('Testing TAPD access...');
  await page.goto('https://www.tapd.cn/31253609/bugtrace/bugs/add', {
    waitUntil: 'domcontentloaded',
    timeout: 20000,
  });

  const url = page.url();
  console.log('URL:', url);

  if (url.includes('login')) {
    console.log('❌ Session invalid');
  } else {
    console.log('✅ Session is valid!');
    const title = await page.title();
    console.log('Page title:', title);

    // 可以保存到文件表示验证通过
    fs.writeFileSync(path.join(WS_DIR, 'memory/tapd_login_verified.txt'), new Date().toISOString(), 'utf8');
  }

  await browser.close();
}

main().catch(err => {
  console.error('FAILED:', err.message);
  process.exit(1);
});

